import React, { useEffect, useState } from "react";

export default function Internship() {
  const [internships, setInternships] = useState([]);
  const [role, setRole] = useState("");
  const [form, setForm] = useState({ role: "", company: "", duration: "" });
  const [editingIndex, setEditingIndex] = useState(null);

  useEffect(() => {
    const loggedInUser = JSON.parse(localStorage.getItem("loggedInUser"));
    if (loggedInUser) setRole(loggedInUser.role);

    const saved = JSON.parse(localStorage.getItem("internships")) || [];
    setInternships(saved);
  }, []);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleAdd = () => {
    if (!form.role || !form.company || !form.duration) return alert("Fill all fields");
    const updated = [...internships, form];
    setInternships(updated);
    localStorage.setItem("internships", JSON.stringify(updated));
    setForm({ role: "", company: "", duration: "" });
  };

  const handleEdit = (index) => {
    setForm(internships[index]);
    setEditingIndex(index);
  };

  const handleUpdate = () => {
    if (!form.role || !form.company || !form.duration) return alert("Fill all fields");
    const updated = [...internships];
    updated[editingIndex] = form;
    setInternships(updated);
    localStorage.setItem("internships", JSON.stringify(updated));
    setForm({ role: "", company: "", duration: "" });
    setEditingIndex(null);
  };

  const handleDelete = (index) => {
    const updated = internships.filter((_, i) => i !== index);
    setInternships(updated);
    localStorage.setItem("internships", JSON.stringify(updated));
  };

  return (
    <div className="p-6 max-w-3xl mx-auto">
      <h1 className="text-3xl font-bold mb-6">Internship Opportunities</h1>

      {(role === "admin" || role === "hr") && (
        <div className="bg-gray-100 p-4 rounded-lg mb-6">
          <h2 className="text-xl font-semibold mb-4">
            {editingIndex !== null ? "Edit Internship" : "Add Internship"}
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4">
            <input
              type="text"
              name="role"
              placeholder="Role"
              value={form.role}
              onChange={handleChange}
              className="border p-2 rounded"
            />
            <input
              type="text"
              name="company"
              placeholder="Company"
              value={form.company}
              onChange={handleChange}
              className="border p-2 rounded"
            />
            <input
              type="text"
              name="duration"
              placeholder="Duration"
              value={form.duration}
              onChange={handleChange}
              className="border p-2 rounded"
            />
          </div>
          {editingIndex !== null ? (
            <button
              onClick={handleUpdate}
              className="bg-blue-600 text-white px-4 py-2 rounded"
            >
              Update
            </button>
          ) : (
            <button
              onClick={handleAdd}
              className="bg-green-600 text-white px-4 py-2 rounded"
            >
              Add
            </button>
          )}
        </div>
      )}

      <div>
        {internships.length === 0 ? (
          <p>No internships available.</p>
        ) : (
          internships.map((item, index) => (
            <div
              key={index}
              className="border p-4 rounded mb-4 shadow flex justify-between items-start"
            >
              <div>
                <h3 className="text-lg font-semibold">{item.role}</h3>
                <p className="text-gray-600">Company: {item.company}</p>
                <p className="text-gray-600">Duration: {item.duration}</p>
              </div>

              {role === "admin" && (
                <div className="space-x-2">
                  <button
                    onClick={() => handleEdit(index)}
                    className="text-blue-600"
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => handleDelete(index)}
                    className="text-red-600"
                  >
                    Delete
                  </button>
                </div>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
}
